import functools

def decorator_with_args(arg1, arg2):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            # 使用 arg1, arg2 定制行为
            result = func(*args, **kwargs)
            return result
        return wrapper
    return decorator

@decorator_with_args(arg1='value1', arg2='value2')
def my_function():
    pass
